n = red_edges[0][0].__len__()
# assert n == 6


vertices = list(itertools.product([0, 1], repeat=n))
vertices = [v[::-1] for v in vertices]
graph = {}
for v in vertices:
    graph[v] = []
    for i in range(n):
        neighbor = [v[j] if i != j else (1 - v[j]) for j in range(n)]
        graph[v].append(tuple(neighbor))


def dist(u, v):
    return sum(1 for x, y in zip(u, v) if x != y)


def antipodal(u):
    return tuple(1 - x for x in u)


def get_num_swaps(red_edges, u):
    """
    Calculate the number of swaps needed to get from u to antipodal u
    """

    def e(u, v):
        return (min(u, v), max(u, v)) in red_edges

    d = {(v, "r"): 0 if e(u, v) else 1000000 for v in graph[u]} | {(v, "b"): 0 if not e(u, v) else 1000000 for v in graph[u]}
    p = {(v, "r"): (u, None) for v in graph[u]} | {(v, "b"): (u, None) for v in graph[u]}

    for k in range(2, n + 1):
        d_new = dict()
        for T in itertools.combinations(range(n), k):
            v = tuple((1 - u[i] if i in T else u[i]) for i in range(n))

            d_new[(v, "r")] = 1000000
            d_new[(v, "b")] = 1000000
            p[(v, "r")] = None
            p[(v, "b")] = None
            for T2 in itertools.combinations(range(n), k - 1):

                w = tuple((1 - u[i] if i in T2 else u[i]) for i in range(n))  # distance k - 1 from u
                if dist(v, w) == 1:

                    edge_present = e(v, w)
                    if edge_present:
                        if d_new[(v, "r")] > d[w, "r"]:
                            d_new[(v, "r")] = d[w, "r"]
                            p[(v, "r")] = (w, "r")

                        if d_new[(v, "r")] > d[w, "b"] + 1:
                            d_new[(v, "r")] = d[w, "b"] + 1
                            p[(v, "r")] = (w, "b")
                    else:
                        if d_new[(v, "b")] > d[w, "r"] + 1:
                            d_new[(v, "b")] = d[w, "r"] + 1
                            p[(v, "b")] = (w, "r")
                        if d_new[(v, "b")] > d[w, "b"]:
                            d_new[(v, "b")] = d[w, "b"]
                            p[(v, "b")] = (w, "b")

        # print(f"Iteration {k}: {d_new}")
        d = d_new

    # Check final path for red and blue
    for c in ["r", "b"]:
        if d[(antipodal(u), c)] >= 10000:
            continue  # Nothing to check
        
        current_color = c
        v = antipodal(u)
        path = []
        while v != u:
            # print(f"Current path: {path}, current vertex: {v}, color: {c}")
            path.append(v)
            v, current_color = p[(v, current_color)]

           
        path.append(u)
        path.reverse()
        # print(f"Path for {c}: {path}")

        # Check whether the number is correct
        num_swaps = 0
        for i in range(2, len(path)):
            if e(path[i - 2], path[i - 1]) != e(path[i - 1], path[i]):
                num_swaps += 1

        # print("Number of swaps for color", c, "from", u, "to", antipodal(u), ":", num_swaps)

        assert num_swaps == d[(antipodal(u), c)], f"Number of swaps for color '{c}' does not match: {num_swaps} != {d[(antipodal(u), c)]}"

    return min(d[(antipodal(u), "r")], d[(antipodal(u), "b")])


blocked_pairs = 0
for u in vertices:
    if u > antipodal(u):
        continue

    if get_num_swaps(red_edges, u) > 1:
        blocked_pairs += 1
        # print(f"Blocked pair: {u} -> {antipodal(u)}")
    else:
        pass
        # print(f"Unblocked pair: {u} -> {antipodal(u)}")

print(f"Number of blocked pairs: {blocked_pairs}")
